"use client";

import {
    createContext,
    useContext,
    useState,
    useCallback,
    useMemo,
    useEffect,
    ReactNode,
} from "react";
import { CartItem } from "@/features/products/types";

interface CartContextValue {
    items: CartItem[];
    addItem: (item: Omit<CartItem, "cartId" | "quantity">) => void;
    removeItem: (cartId: string) => void;
    updateQuantity: (cartId: string, quantity: number) => void;
    itemCount: number;
    total: number;
}

const CartContext = createContext<CartContextValue | null>(null);

export function CartProvider({ children }: { children: ReactNode }) {
    const [items, setItems] = useState<CartItem[]>([]);
    const [isMounted, setIsMounted] = useState(false);

    useEffect(() => {
        setIsMounted(true);
        try {
            const storedCart = localStorage.getItem("mobileStore_cart");
            if (storedCart) {
                setItems(JSON.parse(storedCart));
            }
        } catch (error) {
            console.error("Failed to load cart from local storage", error);
        }
    }, []);

    useEffect(() => {
        if (isMounted) {
            localStorage.setItem("mobileStore_cart", JSON.stringify(items));
        }
    }, [items, isMounted]);

    const addItem = useCallback(
        (newItem: Omit<CartItem, "cartId" | "quantity">) => {
            setItems((prev) => {
                const existing = prev.find(
                    (item) =>
                        item.productId === newItem.productId &&
                        item.storage === newItem.storage &&
                        item.color === newItem.color
                );

                if (existing) {
                    return prev.map((item) =>
                        item.cartId === existing.cartId
                            ? { ...item, quantity: item.quantity + 1 }
                            : item
                    );
                }

                return [
                    ...prev,
                    {
                        ...newItem,
                        cartId: `${newItem.productId}-${newItem.storage}-${newItem.color}`,
                        quantity: 1,
                    },
                ];
            });
        },
        []
    );

    const removeItem = useCallback((cartId: string) => {
        setItems((prev) => prev.filter((item) => item.cartId !== cartId));
    }, []);

    const updateQuantity = useCallback((cartId: string, quantity: number) => {
        if (quantity <= 0) {
            setItems((prev) => prev.filter((item) => item.cartId !== cartId));
            return;
        }
        setItems((prev) =>
            prev.map((item) =>
                item.cartId === cartId ? { ...item, quantity } : item
            )
        );
    }, []);

    const itemCount = useMemo(
        () => items.reduce((sum, item) => sum + item.quantity, 0),
        [items]
    );

    const total = useMemo(
        () => items.reduce((sum, item) => sum + item.price * item.quantity, 0),
        [items]
    );

    const value = useMemo(
        () => ({ items, addItem, removeItem, updateQuantity, itemCount, total }),
        [items, addItem, removeItem, updateQuantity, itemCount, total]
    );

    return <CartContext.Provider value={value}>{children}</CartContext.Provider>;
}

export function useCart() {
    const context = useContext(CartContext);
    if (!context) {
        throw new Error("useCart must be used within a CartProvider");
    }
    return context;
}

import { render, screen, act } from '@testing-library/react';
import { LanguageProvider, useLanguage } from './LanguageContext';

const TestComponent = () => {
    const { language, setLanguage, t } = useLanguage();
    return (
        <div>
            <span data-testid="lang">{language}</span>
            <span data-testid="translation">{t('cart.empty' as any)}</span>
            <span data-testid="missing-translation">{t('non.existent.key' as any)}</span>
            <button onClick={() => setLanguage('en')}>Set EN</button>
        </div>
    );
};

describe('LanguageContext', () => {
    beforeEach(() => {
        localStorage.clear();
    });

    it('provides default spanish translation and fallbacks for missing keys', () => {
        render(
            <LanguageProvider>
                <TestComponent />
            </LanguageProvider>
        );
        expect(screen.getByTestId('lang')).toHaveTextContent('es');
        expect(screen.getByTestId('translation')).toHaveTextContent('Tu carrito está vacío');
        expect(screen.getByTestId('missing-translation')).toHaveTextContent('non.existent.key');
    });

    it('allows language change to english', () => {
        render(
            <LanguageProvider>
                <TestComponent />
            </LanguageProvider>
        );
        act(() => {
            screen.getByText('Set EN').click();
        });

        expect(screen.getByTestId('lang')).toHaveTextContent('en');
        // El translation debería actualizarse
        expect(screen.getByTestId('translation')).toHaveTextContent('Your cart is empty');
        // Debe persistir en localStorage
        expect(localStorage.getItem('language')).toBe('en');
    });

    it('loads language from localStorage on mount', () => {
        localStorage.setItem('language', 'en');
        render(
            <LanguageProvider>
                <TestComponent />
            </LanguageProvider>
        );
        expect(screen.getByTestId('lang')).toHaveTextContent('en');
    });

    it('throws error if useLanguage is used outside LanguageProvider', () => {
        const consoleError = jest.spyOn(console, 'error').mockImplementation(() => { });
        expect(() => render(<TestComponent />)).toThrow('useLanguage must be used within a LanguageProvider');
        consoleError.mockRestore();
    });
});

